INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0.2, 1, 26214, "", 26214071, "", "wac_birthday_talk_kyapi", "", 105211, 3, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", 0, 26214, "", 26214072, "", "vo_wac_26214_002", "", "vo_wac_26214", 21, 0);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0, 10, 26214, 1, 26214073, 0.5, "私もだけど、彼とリンちゃんも準備を\nがんばったのよ♪\nふふっ、シオリちゃんのために～って\n張り切ってたのよね？", 0, 105211, 11, 1);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", "", 26214, "", 26214074, "", "", "", 26214073, 91, "");
