INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", 0, 34314, "", 34314070, "", "vo_wac_34314_000", "", "vo_wac_34314", 21, 0);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0, 10, 34314, 1, 34314071, 0.5, "ついにこの日がやってきたの～！\n今日はミヤコの誕生日なんだから、\n山のようにプリンを用意して、\n盛大にお祝いするの～♪", 0, 100711, 11, 1);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", "", 34314, "", 34314072, "", "", "", 0, 91, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0.2, 1, 34314, "", 34314073, "", "wac_birthday_idle_smile", "", 100711, 3, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0.2, 1, 34314, "", 34314074, "", "wac_birthday_talk_smile", "", 100611, 3, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", 0, 34314, "", 34314075, "", "vo_wac_34314_001", "", "vo_wac_34314", 21, 0);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0, 10, 34314, 1, 34314076, 0.5, "もちろん、甘々で、プルプルのプリンを\nたくさん用意してきたよ～♪\n一度に頬張ったら、お口から\n垂れてきちゃうかも～♪", 0, 100611, 11, 1);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", "", 34314, "", 34314077, "", "", "", 0, 91, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0.2, 1, 34314, "", 34314078, "", "wac_birthday_idle_smile", "", 100611, 3, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0.2, 1, 34314, "", 34314079, "", "wac_birthday_talk_doya", "", 100711, 3, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", 0, 34314, "", 34314080, "", "vo_wac_34314_002", "", "vo_wac_34314", 21, 0);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0, 10, 34314, 1, 34314081, 0.5, "オマエたち、よくわかってるプレゼント\n本当にありがとうなの～♪\n次から誕生日だけじゃなくて、\nお盆と命日にもプリンを寄こすの～", 0, 100711, 11, 1);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", "", 34314, "", 34314082, "", "", "", 0, 91, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0.2, 1, 34314, "", 34314083, "", "wac_birthday_idle_doya", "", 100711, 3, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0.2, 1, 34314, "", 34314084, "", "wac_birthday_talk_sad", "", 102211, 3, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", 0, 34314, "", 34314085, "", "vo_wac_34314_003", "", "vo_wac_34314", 21, 0);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0, 10, 34314, 1, 34314086, 0.5, "ちょっと、欲張り過ぎでしょう！？\n一年に何回もこんなことしたら、\nランドソルからプリンが\n消えちゃうわよ！", 0, 102211, 11, 1);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", "", 34314, "", 34314087, "", "", "", 0, 91, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0.2, 1, 34314, "", 34314088, "", "wac_birthday_idle_sad", "", 102211, 3, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0.2, 1, 34314, "", 34314089, "", "wac_birthday_talk_wish", "", 103111, 3, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", 0, 34314, "", 34314090, "", "vo_wac_34314_004", "", "vo_wac_34314", 21, 0);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0, 10, 34314, 1, 34314091, 0.5, "でも、喜んでもらえてなによりです。\nミヤコさんが明るく振る舞う限り、\n穢れのない魂のまま、\n悪霊に転じることもないでしょう……", 0, 103111, 11, 1);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", "", 34314, "", 34314092, "", "", "", 0, 91, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0.2, 1, 34314, "", 34314093, "", "wac_birthday_idle_wish", "", 103111, 3, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0.2, 1, 34314, "", 34314094, "", "wac_birthday_talk_sad", "", 104411, 3, "");
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", 0, 34314, "", 34314095, "", "vo_wac_34314_005", "", "vo_wac_34314", 21, 0);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0, 10, 34314, 1, 34314096, 0.5, "う～む。\n際限なくプリンを要求してくるのは、\nもう悪霊に片足を突っ込んで\nおらんかのう？", 0, 104411, 11, 1);
