INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0, 10, 37914, 1, 37914058, 0.5, "おおっ、この蝋燭をぼくのために？\nなんと手の込んだ複雑な香りだ。\nその下には大層な土台まで……\nこれはバースデー土台というやつだな！", 0, 111011, 11, 1);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", "", 37914, "", 37914059, "", "", "", 0, 91, "");
