INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0, 10, 38614, 1, 38614069, 0.5, "今日は、私の誕生日を\nお祝いしてくれてありがとう。\nケーキを食べる前に、\n一つだけ質問してもいいかしら？", 0, 105111, 11, 1);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", "", 38614, "", 38614070, "", "", "", 0, 91, "");
