INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", 0, 38614, "", 38614078, "", "vo_wac_38614_002", "", "vo_wac_38614", 21, 0);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES (0, 10, 38614, 1, 38614079, 0.5, "いえ、あのね？\nテーブルの下に、未使用のロウソクが\n大量に袋詰めしてあるんだけど。\nこれは、なに？", 0, 105111, 11, 1);
INSERT INTO `v1_9927ee8bac539b236e096312ac55810a348e7cc9a61e172b6cbc5a0dba777083` VALUES ("", "", 38614, "", 38614080, "", "", "", 0, 91, "");
